const source = $json.output ?? $json;
let text = '';

if (typeof source === 'string') {
  text = source;
} else if (source && typeof source === 'object') {
  if (typeof source.text === 'string') {
    text = source.text;
  } else if (typeof source.texto === 'string') {
    text = source.texto;
  } else if (typeof source.output === 'string') {
    text = source.output;
  } else if (typeof source.content === 'string') {
    text = source.content;
  }
}

if (text === '' && typeof $json.text === 'string') {
  text = $json.text;
}

if (text === '') {
  text = JSON.stringify(source);
}

return [{ json: { output: text.trim() } }];
